local function bvBe32(value)
    value %= BV_U32
    return string.char(
        BV_RSHIFT(value, 24) % 256,
        BV_RSHIFT(value, 16) % 256,
        BV_RSHIFT(value, 8) % 256,
        value % 256
    )
end

local function bvSha256(source)
