local BV_BASE85_MAP = {}
for index = 1, #BV_BASE85 do BV_BASE85_MAP[string.byte(BV_BASE85, index)] = index - 1 end

local function bvBase85Decode(source, expectedSize)
    local output, written, index = BV_BUFFER.create(expectedSize), 0, 1
